{
  "family": "Fries-, Photo-Fries, and Anionic Ortho-Fries Rearrangement",
  "candidate": {
    "substrate_smiles": [
      "CC(=O)Oc1ccccc1"
    ],
    "product_smiles": [
      "O=C(C)c1ccccc1O"
    ],
    "optional_reagent_smiles": [
      "[Al](Cl)(Cl)Cl"
    ],
    "rationale": "The Fries rearrangement of phenyl acetate to 2-hydroxyacetophenone is a classic, simple, and unambiguous textbook example of this reaction family. It clearly demonstrates the core transformation: the migration of an acyl group from a phenolic oxygen to an ortho position on the aromatic ring, catalyzed by a Lewis acid (AlCl3). This example is minimal in structure, avoiding complex substituents that could cause ambiguity.",
    "collision_avoidance_note": "This example uses a simple phenyl acetate substrate, avoiding more complex polycyclic or substituted arenes that could overlap with other named reactions involving aromatic systems. The transformation is a specific acyl migration, distinct from Claisen rearrangements (allyl migration), benzidine rearrangements (diarylamine rearrangement), or Friedel-Crafts acylation (which involves an external acylating agent and an activated arene, not an intramolecular rearrangement of an ester)."
  }
}
